    @Override
    public SOAPMessage invoke(SOAPMessage request) {
        long requestId = REQUEST_COUNTER.incrementAndGet();
        String reqIdStr = "REQ-" + requestId;
        LOGGER.info("Processing request: " + reqIdStr);

        try {
            SOAPBody requestBody = request.getSOAPBody();
            Node firstChild = getFirstElementChild(requestBody);

            if (firstChild == null) {
                return createErrorResponse(reqIdStr, "EMPTY_REQUEST", "No operation found in SOAP body");
            }

            String operation = firstChild.getLocalName();
            LOGGER.info("Operation: " + operation + " for request: " + reqIdStr);

            switch (operation) {
                case "DataImportRequest":
                    return handleDataImport(reqIdStr, (Element) firstChild);
                case "BatchImportRequest":
                    return handleBatchImport(reqIdStr, (Element) firstChild);
                case "QueryRequest":
                    return handleQuery(reqIdStr, (Element) firstChild);
                case "SessionStatusRequest":
                    return handleSessionStatus(reqIdStr, (Element) firstChild);
                case "TransformRequest":
                    return handleTransform(reqIdStr, (Element) firstChild);
                default:
                    return createErrorResponse(reqIdStr, "UNKNOWN_OPERATION",
                            "Unknown operation: " + operation);
            }
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "SOAP error processing request " + reqIdStr, e);
            return createFaultResponse(reqIdStr, "SOAP_ERROR", e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing request " + reqIdStr, e);
            return createFaultResponse(reqIdStr, "INTERNAL_ERROR", e.getMessage());
        }
    }

